<template>
    <b-card no-body class="border-0">
        <b-card-header class="text-center">
            {{ year }}년 {{ month }}월
        </b-card-header>
        <b-card-body>
            <b-row>
                <b-col class="text-center border-0 p-1 mt-1"
                    style="width:18%;"
                >
                </b-col>
                <b-col
                    v-for="label in ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']"
                    :key="label"
                    class="text-center border p-1 mt-1 ml-1"
                    style="width:12%;"
                >
                    {{ label }}
                </b-col>
            </b-row>
            <b-row
                v-for="week in weekList"
                :key="week.label"
            >
                <b-col class="text-center border p-1 mt-1"
                    style="width:18%;"
                >
                    {{ week.month }}월 {{ week.weekOfMonth }}주 <br />
                    {{ week.weekOfYear }}주 / {{ week.maxWeekOfYear }} 주
                </b-col>
                <b-col
                    v-for="date in dateList[week.index]"
                    :key="date.label"
                    class="text-center border p-1 mt-1 ml-1"
                    style="width:12%;"
                >
                    {{ date.label }}
                    <!-- {{ foods[date.ymd] }} -->
                    <template v-if="foods[date.ymd] && foods[date.ymd].foods">
                        <ul class="text-left ml-0" style="padding-inline-start: 0;">
                            <li v-for="food in foods[date.ymd].foods" :key="food.menu" class="ml-0 text-nowrap text-truncate" style="font-size: 0.85em;">
                                {{ foodtype(food.type) }}: {{ food.menu }}
                            </li>
                        </ul>
                    </template>
                </b-col>
            </b-row>
        </b-card-body>
    </b-card>
</template>

<script>
// returns week of the month starting with 0

Date.prototype.getWeekOfYear = function() { 
    var oneJan = new Date(this.getFullYear(), 0, 1); 

    // calculating number of days in given year before given date 
    var numberOfDays = Math.floor((this - oneJan) / (24 * 60 * 60 * 1000)); 

    // adding 1 since this.getDay() 
    //returns value starting from 0 
    return Math.ceil((this.getDay() + 1 + numberOfDays) / 7); 
}

Date.prototype.getMaxWeekOfYear = function() { 
    var lastDay = new Date(this.getFullYear(), 12-1, 31); 
    return lastDay.getWeekOfYear();
}
Date.prototype.getWeekOfMonth = function() {
  var firstWeekday = new Date(this.getFullYear(), this.getMonth(), 1).getDay();
  var offsetDate = this.getDate() + firstWeekday - 1;
//   console.log(this, offsetDate, this.getDate(), firstWeekday);
  return Math.floor(offsetDate / 7);
}
Date.prototype.yyyymmdd = function() {
  var mm = this.getMonth() + 1; // getMonth() is zero-based
  var dd = this.getDate();

  return [this.getFullYear(),
          (mm>9 ? '' : '0') + mm,
          (dd>9 ? '' : '0') + dd
         ].join('');
};

// // german version - week starts with monday
// Date.prototype.getWeekOfMonth = function() {
//   var firstWeekday = new Date(this.getFullYear(), this.getMonth(), 1).getDay() - 1;
//   if (firstWeekday < 0) firstWeekday = 6;
//   var offsetDate = this.getDate() + firstWeekday - 1;
//   return Math.floor(offsetDate / 7);
// }

export default {
    data() {
        return {
            year: 0,
            month: 0,
            date: 0,

            selected: 0,

            weekList: [],
            dateList: {},

            schedule : [
                {
                    title: "aaa",
                    startDate: 20200506,
                    endDate: 20200508,
                    allday: true,
                }
            ],

            foods: {
                20200501: {
                    date: 20200501,
                    foods: [
                        {type: "breakfirst", menu: "곰탕"},
                        {type: "launch", menu: "짜장면"},
                        {type: "dinner", menu: "족발"},
                        {type: "snack", menu: "와플"},
                    ]
                },
                20200502: {
                    date: 20200502,
                    foods: [
                        {type: "breakfirst", menu: "곰탕"},
                        {type: "launch", menu: "짜장면"},
                        {type: "dinner", menu: "족발"},
                        {type: "snack", menu: "핫케잌"},
                    ]
                },
                20200503: {
                    date: 20200503,
                    foods: [
                        {type: "breakfirst", menu: "곰탕"},
                        {type: "launch", menu: "짬뽕"},
                        {type: "dinner", menu: "간장삼겹구이,간장삼겹구이,간장삼겹구이,간장삼겹구이"},
                        {type: "snack", menu: "와플"},
                    ]
                },
                20200504: {
                    date: 20200504,
                    foods: [
                        {type: "breakfirst", menu: "곰탕"},
                        {type: "launch", menu: "짜장면"},
                        {type: "dinner", menu: "족발"},
                        {type: "snack", menu: "와플"},
                    ]
                }
            }
        }
    },
    created() {
        const today = new Date();
        // console.log(today);
        // this.year = today.getFullYear();
        // this.month = today.getMonth() + 1;
        // this.day = today.getDate();

        const firstday = new Date(today.getFullYear(), today.getMonth(), 1);
        const lastday = new Date(today.getFullYear(), today.getMonth() + 1, 0);
        // const day = today.getDay();     // 요일

        // console.log(today, firstday, lastday);
        
        this.year = firstday.getFullYear();
        this.month = firstday.getMonth() + 1;
        this.date = today.getDate();

        const weekCount = Math.ceil((firstday.getDay() + lastday.getDate()) / 7);
        const dateindex = new Date(firstday.getFullYear(), firstday.getMonth(), firstday.getDate());
        dateindex.setDate(dateindex.getDate() - dateindex.getDay());
        // console.log("dateindex", dateindex);
        for(let i = 0; i < weekCount; i++) {
            this.weekList.push({
                month: dateindex.getMonth() + 1,
                weekOfYear: dateindex.getWeekOfYear(),
                maxWeekOfYear: dateindex.getMaxWeekOfYear(),
                weekOfMonth: dateindex.getWeekOfMonth(),
                label: dateindex.getDate(),
                index: i,
            });
            this.dateList[i] = [];
            for(let j = 0; j < 7; j++) {
                // console.log(thisdate);
                this.dateList[i].push({
                    ymd: dateindex.yyyymmdd(),
                    date : dateindex,
                    label : dateindex.getDate()
                });
                dateindex.setDate(dateindex.getDate() + 1);
            }
        }

        // console.log(this.dateList);
    },
    mounted() {
    },
    methods: {
        foodtype(type){
            switch(type) {
                case "breakfirst":
                    return "아침";
                case "launch":
                    return "점심";
                case "dinner":
                    return "저녁";
                case "snack":
                    return "간식";
                default:
                    return "";
            }
        }
    }
}
</script>